        # Priority order for reason reporting
        priority = ["inverted_normals", "not_watertight", "non_manifold", 
                    "degenerate_triangle", "malformed_geometry", "no_faces"]
        for p in priority:
            if p in issue_types:
                reason = p
                break
        if reason is None:
            reason = list(issue_types)[0]

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
        "reason": reason,
    }


def main():
    results = []
    for i in range(1, 21):
        filename = f"supplier_{i:03d}.stl"
        try:
            result = parse_stl(filename)
            entry = {"file": filename, "valid": result["valid"]}
            if not result["valid"]:
                entry["reason"] = result["reason"]
                entry["issues"] = result["issues"]
            print(f"{filename}: valid={result['valid']}, triangles={result['triangle_count']}, "
